function t(r){return r instanceof Date&&!Number.isNaN(r.getTime())}function m(r,n){return r.getFullYear()===n.getFullYear()&&r.getMonth()===n.getMonth()&&r.getDate()===n.getDate()}function u(r){return new Intl.DateTimeFormat("en-US",{weekday:"long",month:"short",day:"numeric"}).format(r)}function e(r){return new Intl.DateTimeFormat("en-US",{hour:"numeric",minute:"2-digit"}).format(r)}function i(r){return`${u(r)} · ${e(r)}`}function o(r,n){return t(r)?!t(n)||r.getTime()===n.getTime()?e(r):`${e(r)} - ${e(n)}`:"TBD"}function c(r,n){return t(r)?!t(n)||r.getTime()===n.getTime()?i(r):m(r,n)?`${u(r)} · ${o(r,n)}`:`${i(r)} - ${i(n)}`:"Date TBD"}function f(r){const n=(r??0)/100;return new Intl.NumberFormat("en-US",{style:"currency",currency:"USD",maximumFractionDigits:0}).format(n)}function a(r){const n=(r??0)/100;return new Intl.NumberFormat("en-US",{style:"currency",currency:"USD",minimumFractionDigits:2,maximumFractionDigits:2}).format(n)}function g(r){if(!r)return"Host";const n=r.trim();return n?n.includes("@")?n.split("@")[0]:n.split(" ")[0]:"Host"}export{f as a,a as b,o as c,i as d,c as f,g};
